export type FeatureType = 'IMAGE' | 'STORY' | 'TRAVEL' | 'TRANSLATE' | 'HOME';

export interface Message {
  role: 'user' | 'assistant';
  content: string;
  imageUrl?: string;
  groundingLinks?: Array<{ title: string; uri: string }>;
}

export interface TravelResult {
  itinerary: string;
  links: Array<{ title: string; uri: string }>;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateImage = async (prompt: string): Promise<string | null> => {
  const ai = getAI();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: { aspectRatio: "1:1" }
      }
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Image generation error:", error);
    throw error;
  }
};

export const generateStory = async (topic: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: topic,
    config: {
      systemInstruction: "You are a creative storyteller. Write a compelling, immersive story based on the user's prompt. Use markdown for formatting.",
    }
  });
  return response.text || "I couldn't write a story this time.";
};

export const planTravel = async (destination: string, location?: { lat: number; lng: number }): Promise<{ text: string, links: any[] }> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Plan a travel itinerary for: ${destination}`,
    config: {
      tools: [{ googleSearch: {} }],
      toolConfig: location ? {
        retrievalConfig: {
          latLng: {
            latitude: location.lat,
            longitude: location.lng
          }
        }
      } : undefined
    }
  });

  return {
    text: response.text || "",
    links: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => chunk.web) || []
  };
};

export const translateText = async (text: string, targetLanguage: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Translate the following text to ${targetLanguage}: "${text}"`,
  });
  return response.text || "Translation failed.";
};

