        case 'IMAGE':
          res = await generateImage(prompt);
          setResult({ type: 'IMAGE', data: res });
          break;
        case 'STORY':
          res = await generateStory(prompt);
          setResult({ type: 'TEXT', data: res });
          break;
        case 'TRAVEL':
          res = await planTravel(prompt, userLocation);
          setResult({ type: 'TRAVEL', data: res.text, links: res.links });
          break;
        case 'TRANSLATE':
          // Simplified for single prompt: "Hello to French"
          const parts = prompt.split(' to ');
          const textToTranslate = parts[0];
          const targetLang = parts[1] || 'Spanish';
          res = await translateText(textToTranslate, targetLang);
          setResult({ type: 'TEXT', data: res });
          break;
