          color="emerald"
          icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>}
          onClick={() => setCurrentView('RECIPE')}
        />
        <FeatureCard 
          title="Translate Text" 
          color="pink"
          icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 5h12M9 3v2m1.048 9.5a18.022 18.022 0 01-3.827-5.802M11 15a11.95 11.95 0 01-2.968-2.815M7.51 5c.67 2.34 2.214 4.478 4.485 6.49m3.234 3.326a2.99 2.99 0 012.828 2.828 2.99 2.99 0 01-2.828 2.828z" /></svg>}
          onClick={() => setCurrentView('TRANSLATE')}
        />
      </div>
    </div>
  );

  return (
    <div className="min-h-screen relative overflow-hidden bg-[#0f172a] text-slate-200">
      {/* Dynamic Background */}
      <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] bg-indigo-600/10 rounded-full blur-[120px] pointer-events-none" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[500px] h-[500px] bg-pink-600/5 rounded-full blur-[120px] pointer-events-none" />

      {/* Top Header */}
      <header className="fixed top-0 left-0 right-0 z-40 p-6 flex justify-between items-center bg-gradient-to-b from-[#0f172a] to-transparent">
        <button onClick={() => setSidebarOpen(true)} className="p-3 glass rounded-2xl hover:bg-white/10 transition-all">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h7" /></svg>
        </button>
        {currentView !== 'HOME' && (
          <div className="font-bold text-xl tracking-tighter mazic-gradient cursor-pointer" onClick={() => {setCurrentView('HOME'); setResult(null)}}>MAZIC</div>
        )}
        <div className="w-10 h-10 rounded-xl glass flex items-center justify-center">
          <div className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse" />
        </div>
      </header>

      <main className="pt-24 pb-32 px-4 max-w-4xl mx-auto overflow-y-auto">
        {currentView === 'HOME' ? renderHome() : (
          <div className="space-y-6 animate-fadeIn">
             <div className="flex items-center justify-between">
                <h2 className="text-2xl font-bold text-white uppercase tracking-widest">{currentView} MODE</h2>
                <button onClick={() => {setCurrentView('HOME'); setResult(null)}} className="text-sm text-gray-400 hover:text-white transition-colors">Close</button>
             </div>
             {isLoading && <LoadingSpinner />}
             {result && (
               <div className="glass p-6 rounded-3xl animate-slideUp border border-white/5">
                 {result.type === 'IMAGE' ? (
                   <img src={result.data} className="rounded-2xl w-full shadow-2xl" alt="Result" />
                 ) : (
                   <div className="prose prose-invert max-w-none text-lg leading-relaxed whitespace-pre-wrap">{result.data}</div>
                 )}
               </div>
             )}
          </div>
        )}
      </main>

      {/* Bottom Input Bar */}
      <div className="fixed bottom-0 left-0 right-0 p-4 md:p-8 bg-gradient-to-t from-[#0f172a] via-[#0f172a]/90 to-transparent z-40">
        <div className="max-w-3xl mx-auto relative">
          {pinnedImage && (
            <div className="absolute bottom-full mb-4 left-4 animate-slideUp">
              <div className="relative group">
                <img src={pinnedImage} className="w-20 h-20 object-cover rounded-xl border-2 border-indigo-500 shadow-xl" />
                <button 
                  onClick={() => setPinnedImage(null)}
                  className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>
            </div>
          )}

          <div className="glass rounded-full p-2 flex items-center shadow-2xl border border-white/10 group focus-within:border-indigo-500/50 transition-all">
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleFileUpload} 
            />
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="p-3 text-gray-400 hover:text-indigo-400 transition-colors"
              title="Pin an image"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
            </button>

            <input 
              type="text"
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleAction()}
              placeholder="What is your Question?"
              className="flex-1 bg-transparent border-none focus:ring-0 text-white px-4 placeholder:text-gray-500 font-medium"
            />

            <button 
              onClick={() => handleAction()}
              disabled={isLoading || (!prompt.trim() && !pinnedImage)}
              className="bg-indigo-600 hover:bg-indigo-500 disabled:bg-gray-700 text-white px-6 py-2 rounded-full font-bold transition-all shadow-lg active:scale-95 flex items-center space-x-2"
            >
              <span>{isLoading ? '...' : 'Send'}</span>
              {!isLoading && <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" /></svg>}
            </button>
          </div>
        </div>
      </div>

      <Sidebar isOpen={sidebarOpen} onClose={() => setSidebarOpen(false)} onNavigate={(v) => setCurrentView(v)} />

      <style>{`
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
        @keyframes slideUp { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fadeIn { animation: fadeIn 0.3s ease-out; }
        .animate-slideUp { animation: slideUp 0.4s cubic-bezier(0.16, 1, 0.3, 1); }
      `}</style>
    </div>
  );
};

export default App;

import React from 'react';

