  icon: React.ReactNode;
  color: string;
  onClick: () => void;
}

export const FeatureCard: React.FC<FeatureCardProps> = ({ title, icon, color, onClick }) => {
  const colorMap: Record<string, string> = {
    blue: 'from-blue-500/20 to-indigo-500/5 text-blue-400 border-blue-500/20',
    purple: 'from-purple-500/20 to-pink-500/5 text-purple-400 border-purple-500/20',
    emerald: 'from-emerald-500/20 to-teal-500/5 text-emerald-400 border-emerald-500/20',
    pink: 'from-pink-500/20 to-red-500/5 text-pink-400 border-pink-500/20',
  };

  return (
    <button 
      onClick={onClick}
      className={`group relative overflow-hidden glass p-6 rounded-3xl transition-all duration-300 hover:scale-[1.02] border border-white/5 flex flex-col items-center justify-center space-y-3 bg-gradient-to-br ${colorMap[color] || colorMap.blue}`}
    >
      <div className="p-3 rounded-2xl bg-white/5 group-hover:scale-110 transition-transform duration-300">
        {icon}
      </div>
      <span className="text-[10px] md:text-xs font-black tracking-[0.2em] text-gray-300 group-hover:text-white transition-colors uppercase text-center">
        {title}
      </span>
    </button>
  );
};
